import { mapState } from "vuex";
import NotImplementedError from "../../utils/errors/NotImplementedError";
export default {
  computed: mapState({
    user: state => state.user,
    summonerIconUrl: state => {
      const {
        host,
        port
      } = state.config.download;
      return `${host}:${port}/summoner_icons/${state.user.summonerIconId}.png`;
    },
    userStatus: state => {
      switch (state.user.summonerStatus) {
        case "ONLINE":
          return "online";
        case "AWAY":
          return "away";
        case "OFFLINE":
          return "offline";
        case "IN_LOBBY":
          return "lobby";
        case "IN_CHAMP_SELECT":
          return "champselect";
        default:
          return "offline";
      }
    }
  }),
  methods: {
    saveUserMotto() {
      const motto = this.$refs.profileMottoInput.value;
      if (motto.length > 30) {
        throw new NotImplementedError("Should show error message for user, or play error sound");
      }
      this.$socket.sendSystemMessage("USER_UPDATE_MOTTO", {
        data: motto
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        this.$store.dispatch("saveUserMotto", motto).then(() => {
          this.$refs.profileMottoInput.blur();
        });
      });
    },
    changeUserStatus() {
      let changeto;
      switch (this.$store.state.user.summonerStatus) {
        case "ONLINE":
          changeto = "AWAY";
          break;
        case "AWAY":
          changeto = "ONLINE";
          break;
        default:
      }
      if (changeto) {
        this.$socket.sendSystemMessage("USER_UPDATE_STATUS", {
          data: changeto
        }, (response, error) => {
          if (error) {
            console.log("Flyback error:");
            console.log(error);
          }
          this.$store.dispatch("saveUserStatus", changeto);
        });
      }
    }
  }
};
